reload() {
  const nextReload = (this.#reloadPromise ?? Promise.resolve())
    .catch(() => {})
    .then(() => this.#reload());
  this.#reloadPromise = nextReload.finally(() => {
    if (this.#reloadPromise === nextReload) {
      this.#reloadPromise = undefined;
    }
  });
}

export async function signJwt<T extends Record<string, unknown>>(
  payload: T,
  options: JWTSignOptions,
): Promise<string> {
  const now = Math.floor(Date.now() / 1000)
  const privateKey = await jose.importPKCS8(
    options.privateKey.replace(/\\n/g, '\n'),
    options.algorithm || 'ES256',
  )

  return new jose.SignJWT(payload)
    .setProtectedHeader({ alg: options.algorithm || 'ES256', kid: options.keyId })
    .setIssuedAt(now)
    .setExpirationTime(options.expiresIn || '5m')
    .sign(privateKey)
}

