function canUseVercelRewrite(proxy: NitroRouteRules["proxy"]): proxy is { to: string } {
  if (!proxy?.to) {
    return false;
  }
  // Must be an external URL
  if (!/^https?:\/\//.test(proxy.to.replace(/\/\*\*$/, ""))) {
    return false;
  }
  // Must not use any ProxyOptions unsupported by Vercel rewrites
  for (const key of UNSUPPORTED_PROXY_OPTIONS) {
    if ((proxy as any)[key] !== undefined) {
      return false;
    }
  }
  return true;
}

async function getDatabase(database: SqliteDatabaseConfig | D1DatabaseConfig, opts: { sqliteConnector?: SQLiteConnector }): Promise<Connector> {
  if (database.type === 'd1') {
    return cloudflareD1Connector({ bindingName: database.bindingName })
  }

  return import(await findBestSqliteAdapter(opts))
    .then((m) => {
      const connector = (m.default || m) as (config: unknown) => Connector
      return connector({ path: database.filename })
    })
}

function findMappedTag(node: MDCElement, tags: Record<string, string>) {
  const tag = node.tag
  if (!tag || typeof node.props?.__ignoreMap !== 'undefined') {
    return tag
  }
  return tags[tag] || tags[pascalCase(tag)] || tags[kebabCase(node.tag)] || tag
}

